import { useEffect, useState } from "react";
import { Link, useNavigate } from "react-router-dom";

function Dashboard() {
  const [questions, setQuestions] = useState([]);
  const [filter, setFilter] = useState("recent");
  const [category, setCategory] = useState("all");

  const navigate = useNavigate();
  const user = JSON.parse(localStorage.getItem("user") || "null");

  useEffect(() => {
    fetch("http://localhost:5000/api/questions")
      .then((res) => res.json())
      .then((data) => setQuestions(data));
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("user");
    navigate("/login");
  };

  // ✅ FILTER LOGIC
  const filtered = questions
    .filter((q) => {
      if (category === "all") return true;
      return q.category === category;
    })
    .sort((a, b) => {
      if (filter === "recent") {
        return new Date(b.createdAt) - new Date(a.createdAt);
      }
      return 0;
    });

  return (
    <div>

      {/* HEADER */}
      <div style={{ display: "flex", justifyContent: "space-between" }}>
        <h2>Dashboard</h2>
        <button onClick={handleLogout}>Logout</button>
      </div>

      {/* FILTERS */}
      <div style={{ marginBottom: "20px" }}>

        <b>Sort:</b>
        <button onClick={() => setFilter("recent")}>Recent</button>
        <button onClick={() => setFilter("popular")}>Popular</button>

        <br /><br />

        <b>Category:</b>
        <button onClick={() => setCategory("all")}>All</button>
        <button onClick={() => setCategory("notes")}>Notes</button>
        <button onClick={() => setCategory("projects")}>Projects</button>
        <button onClick={() => setCategory("guidance")}>Guidance</button>
        <button onClick={() => setCategory("career")}>Career</button>
        <button onClick={() => setCategory("skills")}>Skills</button>

      </div>

      <Link to="/ask">+ Ask Question</Link>

      {/* QUESTIONS */}
      {filtered.map((q) => (
        <div key={q._id} style={{ border: "1px solid gray", margin: "10px", padding: "10px" }}>
          <h3>{q.title}</h3>
          <p>{q.description}</p>
          <p><b>Category:</b> {q.category}</p>

          <Link to={`/answers/${q._id}`}>View</Link>
        </div>
      ))}

    </div>
  );
}

export default Dashboard;
